import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Safety/webdav-site-access.md","filePath":"bn-BD/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"bn-BD/Safety/webdav-site-access.md"};function o(r,e,c,p,h,b){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>Security Settings-এর WebDAV setting আপনার ImgBed site-কে WebDAV endpoint হিসেবে expose করে।</p><p>Enable করার পর Windows, macOS, mobile file managers বা যেকোনো WebDAV-compatible client দিয়ে ImgBed files remote folder-এর মতো browse, upload, delete এবং manage করা যায়।</p><p>এটি site-এর WebDAV access entry। Upload Settings-এর WebDAV storage channel থেকে এটি আলাদা। Upload channel third-party WebDAV service-এ files store করে। এই setting আপনার ImgBed site-কে clients-এর জন্য WebDAV access দিতে সাহায্য করে।</p><h2 id="কোথায়-configure-করবেন" tabindex="-1">কোথায় Configure করবেন <a class="header-anchor" href="#কোথায়-configure-করবেন" aria-label="Permalink to &quot;কোথায় Configure করবেন&quot;">​</a></h2><p>Admin panel খুলে যান:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="এই-feature-কী-করে" tabindex="-1">এই Feature কী করে <a class="header-anchor" href="#এই-feature-কী-করে" aria-label="Permalink to &quot;এই Feature কী করে&quot;">​</a></h2><p>WebDAV enabled হলে ImgBed একটি fixed access URL দেয়:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>আপনার ImgBed file directory-তে connect করতে এই URL ব্যবহার করুন।</p><p>ভালো use cases:</p><ul><li>Computer file manager থেকে সরাসরি ImgBed files browse করা।</li><li>Images WebDAV folder-এ drag করে upload করা।</li><li>Local file manager থেকে ImgBed folders organize করা।</li><li>WebDAV-compatible software দিয়ে images sync বা manage করা।</li><li>Admin panel না খুলে ImgBed content access করা।</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>WebDAV endpoint চালু করে।</p><p>Disabled থাকলে clients WebDAV দিয়ে connect করতে পারবে না।</p><h3 id="username-এবং-password" tabindex="-1">Username এবং Password <a class="header-anchor" href="#username-এবং-password" aria-label="Permalink to &quot;Username এবং Password&quot;">​</a></h3><p>WebDAV clients connect করার সময় এই credentials ব্যবহার করে।</p><p>Dedicated WebDAV username এবং password ব্যবহার করুন। Admin password বা upload password reuse করবেন না।</p><p>Username বা password empty হলে WebDAV clients ঠিকভাবে connect করতে পারবে না।</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode ঠিক করে WebDAV clients images পড়ার সময় কোন image URL prefer করবে।</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed context অনুযায়ী নির্বাচন করে। Normal use-এর জন্য recommended।</td></tr><tr><td>Original</td><td>Original images prefer করে।</td></tr><tr><td>Thumbnail</td><td>Thumbnails prefer করে। Fast preview-এর জন্য useful।</td></tr></tbody></table><p>নিশ্চিত না হলে <code>Smart loading</code> রাখুন।</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel WebDAV uploads-এর জন্য ব্যবহার হয়।</p><p>Windows বা অন্য client থেকে WebDAV directory-তে files copy করলে ImgBed selected default upload channel দিয়ে সেগুলো upload করে।</p><p>Default channel selected না থাকলে browsing কাজ করতে পারে, কিন্তু uploads fail করতে পারে।</p><h2 id="windows-11-এ-webdav-access-করা" tabindex="-1">Windows 11-এ WebDAV Access করা <a class="header-anchor" href="#windows-11-এ-webdav-access-করা" aria-label="Permalink to &quot;Windows 11-এ WebDAV Access করা&quot;">​</a></h2><p>Windows 11 WebDAV-কে network location হিসেবে add করতে পারে।</p><ol><li><code>This PC</code> খুলুন।</li><li><code>Add a network location</code> নির্বাচন করুন।</li><li><code>https://your-domain.com/dav</code> দিন।</li><li>Prompt এলে WebDAV username এবং password দিন।</li><li>Wizard finish করুন। এরপর WebDAV directory File Explorer-এ খোলা যাবে।</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>Add করার পর WebDAV directory Windows File Explorer-এ দেখা যায়। Normal folder-এর মতো files open, copy এবং manage করতে পারবেন।</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>Successful WebDAV connection-এর পর সাধারণত করতে পারবেন:</p><ul><li>Files এবং folders দেখা।</li><li>Files upload করা।</li><li>Folders create করা।</li><li>Files বা folders rename করা।</li><li>Files move করা।</li><li>Files delete করা।</li></ul><p>WebDAV everyday access এবং small-scale file management-এর জন্য ভালো। Large moves, bulk deletes বা complex organization-এর জন্য admin panel ব্যবহার করুন।</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Successful WebDAV connections Login Device Management-এর WebDAV tab-এও দেখা যায়।</p><p>সেখানে WebDAV clients review করতে এবং দরকার হলে পুরোনো devices force offline করতে পারেন।</p><p>WebDAV username বা password বদলালে পুরোনো clients-কে আবার sign in করতে হবে।</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-বারবার-username-এবং-password-চাইছে" tabindex="-1">Windows বারবার Username এবং Password চাইছে <a class="header-anchor" href="#windows-বারবার-username-এবং-password-চাইছে" aria-label="Permalink to &quot;Windows বারবার Username এবং Password চাইছে&quot;">​</a></h3><p>Check করুন:</p><ul><li>URL <code>https://your-domain.com/dav</code>।</li><li>Username এবং password WebDAV settings-এর সঙ্গে match করছে।</li><li>WebDAV enabled।</li><li>Site HTTPS দিয়ে access করা যায়।</li></ul><h3 id="browsing-কাজ-করছে-কিন্তু-upload-fail-হচ্ছে" tabindex="-1">Browsing কাজ করছে, কিন্তু Upload fail হচ্ছে <a class="header-anchor" href="#browsing-কাজ-করছে-কিন্তু-upload-fail-হচ্ছে" aria-label="Permalink to &quot;Browsing কাজ করছে, কিন্তু Upload fail হচ্ছে&quot;">​</a></h3><p><code>Default channel</code> check করুন।</p><p>WebDAV uploads-এর জন্য default upload channel দরকার। সেটি missing, disabled বা misconfigured হলে uploads fail করতে পারে।</p><h3 id="access-speed-unstable" tabindex="-1">Access Speed unstable <a class="header-anchor" href="#access-speed-unstable" aria-label="Permalink to &quot;Access Speed unstable&quot;">​</a></h3><p>WebDAV performance client, network, file count এবং default upload channel-এর ওপর depend করে।</p><p>Directory-তে অনেক files থাকলে এক directory-তে সব না রেখে folders-এ organize করুন।</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>WebDAV access-এর জন্য HTTPS ব্যবহার করুন।</li><li>Strong password set করুন।</li><li>WebDAV password untrusted মানুষের সঙ্গে share করবেন না।</li><li>ব্যবহার না করলে WebDAV বন্ধ রাখুন।</li><li>Login Device Management-এ unused WebDAV devices periodically clean up করুন।</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients browser upload page-এর large-file chunking flow ব্যবহার করে না। নিচের suggested limits-এর বেশি files হলে web upload page ব্যবহার করুন।</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(n,[["render",o]]);export{m as __pageData,f as default};
